INSERT INTO bible_verses (book_id, chapter, verse, text_kjv, text_tagalog) VALUES
  ('11111111-1111-1111-1111-111111111001', 1, 1, 'In the beginning God created the heaven and the earth.', 'Sa pasimula ay nilalang ng Dios ang langit at ang lupa.', 'Genesis 1:1'),
  ('11111111-1111-1111-1111-111111111001', 1, 2, 'And the earth was without form, and void; and darkness was upon the face of the deep. And the Spirit of God moved upon the face of the waters.', 'At ang lupa ay walang anyo, at walang laman; at ang kadiliman ay nasa ibabaw ng kalaliman. At ang Espiritu ng Dios ay kumikilos sa ibabaw ng mga tubig.', 'Genesis 1:2'),
  ('11111111-1111-1111-1111-111111111001', 1, 3, 'And God said, Let there be light: and there was light.', 'At sinabi ng Dios, Magkaroon ng liwanag: at nagkaroon ng liwanag.', 'Genesis 1:3'),
  ('11111111-1111-1111-1111-111111111001', 1, 4, 'And God saw the light, that it was good: and God divided the light from the darkness.', 'At nakita ng Dios na mabuti ang liwanag: at hinati ng Dios ang liwanag sa kadiliman.', 'Genesis 1:4'),
  ('11111111-1111-1111-1111-111111111001', 1, 5, 'And God called the light Day, and the darkness he called Night. And the evening and the morning were the first day.', 'At tinawag ng Dios ang liwanag na Araw, at ang kadiliman ay tinawag niyang Gabi. At nang gabi at nang umaga ay ang unang araw.', 'Genesis 1:5'),
  ('11111111-1111-1111-1111-111111111001', 1, 6, 'And God said, Let there be a firmament in the midst of the waters, and let it divide the waters from the waters.', 'At sinabi ng Dios, Magkaroon ng isang kalawakan sa gitna ng mga tubig, at hatiin nito ang mga tubig sa mga tubig.', 'Genesis 1:6'),
  ('11111111-1111-1111-1111-111111111001', 1, 7, 'And God made the firmament, and divided the waters which were under the firmament from the waters which were above the firmament: and it was so.', 'At ginawa ng Dios ang kalawakan, at hinati ang mga tubig na nasa ilalim ng kalawakan sa mga tubig na nasa itaas ng kalawakan: at nagkagayon.', 'Genesis 1:7'),
  ('11111111-1111-1111-1111-111111111001', 1, 8, 'And God called the firmament Heaven. And the evening and the morning were the second day.', 'At tinawag ng Dios ang kalawakan na Langit. At nang gabi at nang umaga ay ang ikalawang araw.', 'Genesis 1:8'),
  ('11111111-1111-1111-1111-111111111001', 1, 9, 'And God said, Let the waters under the heaven be gathered together unto one place, and let the dry land appear: and it was so.', 'At sinabi ng Dios, Magtipon-tipon ang mga tubig na nasa ilalim ng langit sa isang lugar, at lumitaw ang tuyong lupa: at nagkagayon.', 'Genesis 1:9'),
  ('11111111-1111-1111-1111-111111111001', 1, 10, 'And God called the dry land Earth; and the gathering together of the waters called he Seas: and God saw that it was good.', 'At tinawag ng Dios ang tuyong lupa na Lupa; at ang pagtitipon ng mga tubig ay tinawag niyang mga Dagat: at nakita ng Dios na mabuti.', 'Genesis 1:10'),
  ('11111111-1111-1111-1111-111111111001', 1, 11, 'And God said, Let the earth bring forth grass, the herb yielding seed, and the fruit tree yielding fruit after his kind, whose seed is in itself, upon the earth: and it was so.', 'At sinabi ng Dios, Maglabas ang lupa ng damo, ng halamang nagbubunga ng binhi, at ng punong nagbubunga ng bunga ayon sa kanyang uri, na ang binhi ay nasa kanya mismo, sa ibabaw ng lupa: at nagkagayon.', 'Genesis 1:11'),
  ('11111111-1111-1111-1111-111111111001', 1, 12, 'And the earth brought forth grass, and herb yielding seed after his kind, and the tree yielding fruit, whose seed was in itself, after his kind: and God saw that it was good.', 'At naglabas ang lupa ng damo, at halamang nagbubunga ng binhi ayon sa kanyang uri, at ng punong nagbubunga ng bunga, na ang binhi ay nasa kanya mismo, ayon sa kanyang uri: at nakita ng Dios na mabuti.', 'Genesis 1:12'),
  ('11111111-1111-1111-1111-111111111001', 1, 13, 'And the evening and the morning were the third day.', 'At nang gabi at nang umaga ay ang ikatlong araw.', 'Genesis 1:13'),
  ('11111111-1111-1111-1111-111111111001', 1, 14, 'And God said, Let there be lights in the firmament of the heaven to divide the day from the night; and let them be for signs, and for seasons, and for days, and years:', 'At sinabi ng Dios, Magkaroon ng mga liwanag sa kalawakan ng langit upang hatiin ang araw sa gabi; at sila ay magiging mga palatandaan, at mga panahon, at mga araw, at mga taon:', 'Genesis 1:14'),
  ('11111111-1111-1111-1111-111111111001', 1, 15, 'And let them be for lights in the firmament of the heaven to give light upon the earth: and it was so.', 'At sila ay magiging mga liwanag sa kalawakan ng langit upang magbigay-liwanag sa ibabaw ng lupa: at nagkagayon.', 'Genesis 1:15'),
  ('11111111-1111-1111-1111-111111111001', 1, 16, 'And God made two great lights; the greater light to rule the day, and the lesser light to rule the night: he made the stars also.', 'At ginawa ng Dios ang dalawang dakilang liwanag; ang mas dakilang liwanag upang maghari sa araw, at ang mas maliit na liwanag upang maghari sa gabi: ginawa rin niya ang mga bituin.', 'Genesis 1:16'),
  ('11111111-1111-1111-1111-111111111001', 1, 17, 'And God set them in the firmament of the heaven to give light upon the earth,', 'At inilagay sila ng Dios sa kalawakan ng langit upang magbigay-liwanag sa ibabaw ng lupa,', 'Genesis 1:17'),
  ('11111111-1111-1111-1111-111111111001', 1, 18, 'And to rule over the day and over the night, and to divide the light from the darkness: and God saw that it was good.', 'At upang maghari sa araw at sa gabi, at upang hatiin ang liwanag sa kadiliman: at nakita ng Dios na mabuti.', 'Genesis 1:18'),
  ('11111111-1111-1111-1111-111111111001', 1, 19, 'And the evening and the morning were the fourth day.', 'At nang gabi at nang umaga ay ang ikaapat na araw.', 'Genesis 1:19'),
  ('11111111-1111-1111-1111-111111111001', 1, 20, 'And God said, Let the waters bring forth abundantly the moving creature that hath life, and fowl that may fly above the earth in the open firmament of heaven.', 'At sinabi ng Dios, Magpakasagana ang mga tubig ng mga hayop na may buhay na gumagalaw, at mga ibon na lumilipad sa ibabaw ng lupa sa buong kalawakan ng langit.', 'Genesis 1:20'),
  ('11111111-1111-1111-1111-111111111001', 1, 21, 'And God created great whales, and every living creature that moveth, which the waters brought forth abundantly, after their kind, and every winged fowl after his kind: and God saw that it was good.', 'At nilalang ng Dios ang mga malalaking isda, at bawa''t hayop na buhay na gumagalaw, na ipinanganak ng mga tubig na may kasaganaan, ayon sa kanilang mga uri, at bawa''t ibong may pakpak ayon sa kanyang uri: at nakita ng Dios na mabuti.', 'Genesis 1:21'),
  ('11111111-1111-1111-1111-111111111001', 1, 22, 'And God blessed them, saying, Be fruitful, and multiply, and fill the waters in the seas, and let fowl multiply in the earth.', 'At binasbasan sila ng Dios, na sinabi, Magpakasagana kayo, at magpakarami, at punuin ang mga tubig sa mga dagat, at magpakarami ang mga ibon sa ibabaw ng lupa.', 'Genesis 1:22'),
  ('11111111-1111-1111-1111-111111111001', 1, 23, 'And the evening and the morning were the fifth day.', 'At nang gabi at nang umaga ay ang ikalimang araw.', 'Genesis 1:23'),
  ('11111111-1111-1111-1111-111111111001', 1, 24, 'And God said, Let the earth bring forth the living creature after his kind, cattle, and creeping thing, and beast of the earth after his kind: and it was so.', 'At sinabi ng Dios, Maglabas ang lupa ng hayop na buhay ayon sa kanyang uri, hayop na maamo, at hayop na gumagapang, at hayop na nasa lupa ayon sa kanyang uri: at nagkagayon.', 'Genesis 1:24'),
  ('11111111-1111-1111-1111-111111111001', 1, 25, 'And God made the beast of the earth after his kind, and cattle after their kind, and every thing that creepeth upon the earth after his kind: and God saw that it was good.', 'At ginawa ng Dios ang mga hayop sa lupa ayon sa kanilang mga uri, at ang mga hayop na maamo ayon sa kanilang mga uri, at ang lahat ng gumagapang sa ibabaw ng lupa ayon sa kanyang uri: at nakita ng Dios na mabuti.', 'Genesis 1:25'),
  ('11111111-1111-1111-1111-111111111001', 1, 26, 'And God said, Let us make man in our image, after our likeness: and let them have dominion over the fish of the sea, and over the fowl of the air, and over the cattle, and over all the earth, and over every creeping thing that creepeth upon the earth.', 'At sinabi ng Dios, Gumawa tayo ng tao sa ating larawan, ayon sa ating anyo: at sila ay magkaroon ng kapangyarihan sa mga isda sa dagat, at sa mga ibon sa langit, at sa mga hayop na maamo, at sa buong lupa, at sa lahat ng hayop na gumagapang sa ibabaw ng lupa.', 'Genesis 1:26'),
  ('11111111-1111-1111-1111-111111111001', 1, 27, 'So God created man in his own image, in the image of God created he him; male and female created he them.', 'At nilalang ng Dios ang tao sa kanyang larawan, sa larawan ng Dios nilalang niya siya; lalaki at babae nilalang niya sila.', 'Genesis 1:27'),
  ('11111111-1111-1111-1111-111111111001', 1, 28, 'And God blessed them, and God said unto them, Be fruitful, and multiply, and replenish the earth, and subdue it: and have dominion over the fish of the sea, and over the fowl of the air, and over every living thing that moveth upon the earth.', 'At binasbasan sila ng Dios, at sinabi sa kanila, Magpakasagana kayo, at magpakarami, at punuin ang lupa, at sakupin ninyo: at magkaroon ng kapangyarihan sa mga isda sa dagat, at sa mga ibon sa langit, at sa lahat ng hayop na buhay na gumagalaw sa ibabaw ng lupa.', 'Genesis 1:28'),
  ('11111111-1111-1111-1111-111111111001', 1, 29, 'And God said, Behold, I have given you every herb bearing seed, which is upon the face of all the earth, and every tree, in the which is the fruit of a tree yielding seed; to you it shall be for meat.', 'At sinabi ng Dios, Narito, ibinigay ko sa inyo ang lahat ng halamang nagbubunga ng binhi, na nasa ibabaw ng buong lupa, at ang lahat ng puno, na may bunga ng puno na nagbubunga ng binhi; sa inyo ito magiging pagkain.', 'Genesis 1:29'),
  ('11111111-1111-1111-1111-111111111001', 1, 30, 'And to every beast of the earth, and to every fowl of the air, and to every thing that creepeth upon the earth, wherein there is life, I have given every green herb for meat: and it was so.', 'At sa lahat ng hayop sa lupa, at sa lahat ng ibon sa langit, at sa lahat ng gumagapang sa ibabaw ng lupa, na may buhay, ibinigay ko ang lahat ng berdeng halamang pagkain: at nagkagayon.', 'Genesis 1:30'),
  ('11111111-1111-1111-1111-111111111001', 1, 31, 'And God saw every thing that he had made, and, behold, it was very good. And the evening and the morning were the sixth day.', 'At nakita ng Dios ang lahat ng kanyang ginawa, at, narito, ay napakabuti. At nang gabi at nang umaga ay ang ikaanim na araw.', 'Genesis 1:31')
INSERT INTO bible_verses (book_id, chapter, verse, text_kjv, text_tagalog) VALUES
  ('11111111-1111-1111-1111-111111111019', 23, 1, 'The LORD is my shepherd; I shall not want.', 'Ang Panginoon ay aking pastol; hindi ako mangangailangan.', 'Psalm 23:1'),
  ('11111111-1111-1111-1111-111111111019', 23, 2, 'He maketh me to lie down in green pastures: he leadeth me beside the still waters.', 'Pinalilipad niya ako sa mga berdeng pastulan: hinahatid niya ako sa mga tubig na tahimik.', 'Psalm 23:2'),
  ('11111111-1111-1111-1111-111111111019', 23, 3, 'He restoreth my soul: he leadeth me in the paths of righteousness for his name''s sake.', 'Binubuhay niya ulit ang aking kaluluwa: hinahatid niya ako sa mga landas ng katuwiran dahil sa kanyang pangalan.', 'Psalm 23:3'),
  ('11111111-1111-1111-1111-111111111019', 23, 4, 'Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me.', 'Oo, kahit ako ay lumakad sa lambak ng anino ng kamatayan, hindi ako matakot sa kasamaan: sapagka''t ikaw ay kasama ko; ang iyong tungkod at iyong pamalo ay nagpapasaya sa akin.', 'Psalm 23:4'),
  ('11111111-1111-1111-1111-111111111019', 23, 5, 'Thou preparest a table before me in the presence of mine enemies: thou anointest my head with oil; my cup runneth over.', 'Ihahanda mo ang isang mesa sa harap ko sa harapan ng aking mga kaaway: pinahiran mo ang aking ulo ng langis; ang aking tasa ay umaapaw.', 'Psalm 23:5'),
  ('11111111-1111-1111-1111-111111111019', 23, 6, 'Surely goodness and mercy shall follow me all the days of my life: and I will dwell in the house of the LORD for ever.', 'Totoo na ang kabutihan at habag ay susundan ako sa lahat ng araw ng aking buhay: at ako ay mananahan sa bahay ng Panginoon magpakailanman.', 'Psalm 23:6')
